                    document.getElementsByClassName('browser-body')[0].innerHTML = '';
                    fetch("/run", {
                        body: "level=1&sql=" + current_sql,
                        headers: {
                            "Content-Type": "application/x-www-form-urlencoded",
                        },
                        method: "post",
                    }).then(function (resp) {
                        resp.json().then(function (data) {
                            if( data.hasOwnProperty('sql') && data.hasOwnProperty('error') && data.hasOwnProperty('message') && data.hasOwnProperty('results') ){
                                if( data.sql ){
                                    if( data.error ){
                                        document.getElementsByClassName('browser-body')[0].innerHTML = data.message;
                                    }else{
                                        document.getElementsByClassName('browser-body')[0].innerHTML = '<h3>' + data.results[0].subject + '</h3><p>Article ID: ' + data.results[0].id + '</p><div>' + data.results[0].content + '</div>';
                                    }
                                }else{
                                    document.getElementsByClassName('browser-body')[0].innerHTML = data.message;
                                }
                            }else{
                                //document.getElementsByClassName('sql-results')[0].innerHTML = 'Request failed, please try again';
                            }
                        })
                    });




                }else{
                    alert('URL Invalid 404');
                }
            }
        });




        function writeQuery(str) {
            let qry = "select * from article where id = "+str;
            current_sql = qry;
            if( qry.includes('--') ){
                qry = qry.replace('--','<span style="color:#737373">--') + '</span>';
            }
            if( qry.includes(';') ){
                qry = qry.replace(';','<span style="color:#737373">;') + '</span>';
            }
            document.getElementsByClassName('sql-query')[0].innerHTML = qry;
        }




        writeQuery('1');

    </script>

